export function getAutogeneratedBanner(commentStyle: TypeGenCommentStyle): string {
  // no leading blank line â€” a blank first line is non-idiomatic everywhere and gofmt strips it
  return AUTOGENERATED_BANNER_LINES.map((line) => `${commentStyle} ${line}`).join('\n');
}
